class FoodRatings {
public:
    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        for (int i = 0; i < foods.size(); i++) {
            rating[foods[i]] = ratings[i];
            cuisineRating[cuisines[i]].push_back({ratings[i], foods[i]});
        }
        for (auto& p : cuisineRating) {
            sort(p.second.begin(), p.second.end(), greater<>());
        }
    }

    void changeRating(string food, int newRating) {
        rating[food] = newRating;
        for (auto& p : cuisineRating) {
            for (auto& q : p.second) {
                if (q.second == food) {
                    p.second.erase(remove(p.second.begin(), p.second.end(), q), p.second.end());
                    p.second.push_back({newRating, food});
                    sort(p.second.begin(), p.second.end(), greater<>());
                    return;
                }
            }
        }
    }

    string highestRated(string cuisine) {
        return cuisineRating[cuisine][0].second;
    }
private:
    unordered_map<string, int> rating;
    unordered_map<string, vector<pair<int, string>>> cuisineRating;
};
```
